from together import Together
import os
import datetime

# ---------------------------------------------------------
# Configuration
# ---------------------------------------------------------
api_key = "tgp_v1_5DGhZ0hxAwmGKuR0WD_TfmoV0FTgWlHoym6h2G3FWJc"
client = Together(api_key=api_key)

base_path = "/Users/alex-lirio-lucian/WaterUse——alex/LLM_Prompting"

# Input: The report generated by unified_ab_test.py
input_report_path = os.path.join(base_path, "Unified_Comparison_Report.md")

# Output: The detailed analytical breakdown
output_analysis_path = os.path.join(base_path, "AB_Detailed_Analysis.md")

# The Analyzer Model (Llama-3.3 is excellent for structured comparative analysis)
analyzer_model = "meta-llama/Llama-3.3-70B-Instruct-Turbo"

def run_ab_analysis():
    print(f"📊 Deep Analyzer [{analyzer_model}] is reading the A/B test results...")

    try:
        with open(input_report_path, "r", encoding="utf-8") as f:
            content = f.read()
    except FileNotFoundError:
        print(f"❌ Report not found: {input_report_path}. Please run 'unified_ab_test.py' first.")
        return

    # ---------------------------------------------------------
    # The Deep Analysis Prompt
    # ---------------------------------------------------------
    analysis_prompt = f"""
    You are an expert Institutional Analyst and Game Theory Reviewer. 
    I have conducted an A/B test comparing an [OLD Version] and a [NEW Version] of a prompt for extracting Action Situations from an ODD+D document.

    Here is the comparison report containing outputs from different AI models:
    === REPORT START ===
    {content}
    === REPORT END ===

    Your task is to deeply analyze the differences between the OLD and NEW outputs for EACH model.
    Provide a structured evaluation formatted in Markdown. For every model in the report, output the following sections:

    ### 1. 🏆 Overall Winner for [Model Name]
    State clearly whether the [OLD Version] or [NEW Version] performed better.

    ### 2. 📈 Strategic Benefits & Wins (Why the winner won)
    Detail the specific strategies or analytical depth where the winner excelled. 
    - E.g., "The NEW version correctly implemented spatial asymmetry (Upstream vs Downstream impacts), which provided a realistic representation of water flow."
    - Try to quantify the analytical benefit (e.g., "The New version identified 4 distinct dilemmas compared to the Old's 2, increasing strategic coverage by 100%").

    ### 3. 🛑 Blind Spots & Ignored Elements (Where the loser failed)
    Identify exactly what the losing version missed, ignored, or hallucinated.
    - Did it fail to mention Ecological Thresholds (tipping points/fish collapse)?
    - Did it create perfectly symmetric payoff matrices for asymmetric scenarios?
    - Did it hallucinate technologies not in the text?

    ### 4. 💡 Key Takeaway for Prompt Engineering
    One sentence summarizing what the NEW prompt text successfully fixed or what still needs fixing.

    Keep your analysis sharp, objective, and strictly based on the provided text.
    """

    print("   ↳ Analyzer is computing the strategic differences (this may take a minute)...")
    try:
        response = client.chat.completions.create(
            model=analyzer_model,
            messages=[
                {"role": "system", "content": "You are a sharp, analytical AI reviewer comparing text generation outputs."},
                {"role": "user", "content": analysis_prompt}
            ],
            temperature=0.2 # Low temperature for highly analytical and consistent outputs
        )

        analysis_text = response.choices[0].message.content

        # Save the Analysis Report
        with open(output_analysis_path, "w", encoding="utf-8") as f:
            f.write("# 📊 A/B Test Deep Analysis Report\n")
            f.write(f"> Generated at: {datetime.datetime.now().strftime('%Y-%m-%d %H:%M:%S')}\n")
            f.write(f"> Source File: `{os.path.basename(input_report_path)}`\n\n")
            f.write(analysis_text)

        print(f"✅ Analysis Complete! Detailed breakdown saved to: {output_analysis_path}")
        print("👉 Open this file in Markdown format to see the exact strategic wins and missing elements.")

    except Exception as e:
        print(f"❌ Analysis failed: {e}")

if __name__ == "__main__":
    run_ab_analysis()